class TestFlattenHappyPath:
    """Tests for normal, expected use cases"""

    def test_flatten_single_level_list(self):
        """Test flattening a list with no nested lists"""
        assert flatten([1, 2, 3, 4]) == [1, 2, 3, 4]

    def test_flatten_two_level_nested_list(self):
        """Test flattening a list with one level of nesting"""
        assert flatten([1, [2, 3], 4]) == [1, 2, 3, 4]

    def test_flatten_deeply_nested_list(self):
        """Test flattening a list with multiple levels of nesting"""
        assert flatten([1, [2, [3, [4, 5]]], 6]) == [1, 2, 3, 4, 5, 6]

    def test_flatten_mixed_types(self):
        """Test flattening with mixed data types"""
        assert flatten([1, "hello", [2.5, "world"], [3]]) == [1, "hello", 2.5, "world", 3]

    def test_flatten_all_nested(self):
        """Test flattening when all elements are nested"""
        assert flatten([[1], [2], [3]]) == [1, 2, 3]

    def test_flatten_strings_not_iterated(self):
        """Test that strings are treated as atomic values, not iterated"""
        assert flatten(["hello", ["world"]]) == ["hello", "world"]


